use fastly::backend::{BackendBuilder, BackendHealthState, Builder};
use fastly::{Error, Request, Response};

fn build_backend(name: &str, host: &str, port: u16, use_tls: bool) -> Result<fastly::backend::Backend, Error> {
    let mut builder = BackendBuilder::new(name, host);
    builder.port(port);

    if use_tls {
        builder.enable_ssl();
        builder.sni_hostname(host);
        builder.check_certificate(true);
        builder.ca_certificate(None);
    } else {
        builder.disable_ssl();
    }

    builder.finish()
}

